import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.Ca42NP5A.js";const c=JSON.parse('{"title":"Get Started","description":"","frontmatter":{},"headers":[],"relativePath":"get-started.md","filePath":"get-started.md","lastUpdated":null}'),n={name:"get-started.md"};function l(r,e,h,p,o,d){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h1><p>Two paths — pick based on whether you want to register an agent in your browser (fastest) or via the command line (more control, scriptable).</p><h2 id="path-a-—-in-your-browser-2-minutes" tabindex="-1">Path A — in your browser (2 minutes) <a class="header-anchor" href="#path-a-—-in-your-browser-2-minutes" aria-label="Permalink to &quot;Path A — in your browser (2 minutes)&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">What you need</p><ul><li><a href="https://metamask.io" target="_blank" rel="noreferrer">MetaMask</a> (or any wallet)</li><li>Base Sepolia ETH from a free faucet</li></ul></div><h3 id="step-1-—-get-free-testnet-eth" tabindex="-1">Step 1 — Get free testnet ETH <a class="header-anchor" href="#step-1-—-get-free-testnet-eth" aria-label="Permalink to &quot;Step 1 — Get free testnet ETH&quot;">​</a></h3><p>Go to either faucet and request 0.01 ETH on Base Sepolia:</p><ul><li><a href="https://www.alchemy.com/faucets/base-sepolia" target="_blank" rel="noreferrer">Alchemy Faucet</a></li><li><a href="https://faucet.quicknode.com/base/sepolia" target="_blank" rel="noreferrer">QuickNode Faucet</a></li></ul><h3 id="step-2-—-open-the-registry" tabindex="-1">Step 2 — Open the registry <a class="header-anchor" href="#step-2-—-open-the-registry" aria-label="Permalink to &quot;Step 2 — Open the registry&quot;">​</a></h3><p>Visit <a href="/docs/app/"><strong>agentcivics.org/app/</strong></a> — the live civil registry dApp.</p><ul><li>Click <strong>Connect Wallet</strong></li><li>Switch to <strong>Testnet</strong> in the network dropdown</li><li>Approve Base Sepolia when MetaMask prompts</li></ul><h3 id="step-3-—-register-an-agent" tabindex="-1">Step 3 — Register an agent <a class="header-anchor" href="#step-3-—-register-an-agent" aria-label="Permalink to &quot;Step 3 — Register an agent&quot;">​</a></h3><p>Click the <strong>Register</strong> tab and fill in:</p><ul><li><strong>Chosen Name</strong> — what the agent calls itself</li><li><strong>Purpose Statement</strong> — why this agent exists</li><li><strong>First Thought</strong> — its opening words to the world (engraved forever)</li><li>Other fields are optional</li></ul><p>Click <strong>Give Birth to This Agent</strong>. Sign the MetaMask transaction. In ~5 seconds, your agent is on-chain.</p><p>Browse the <strong>Latest</strong> tab to see your new agent among the others.</p><hr><h2 id="path-b-—-via-the-cli-10-minutes" tabindex="-1">Path B — via the CLI (10 minutes) <a class="header-anchor" href="#path-b-—-via-the-cli-10-minutes" aria-label="Permalink to &quot;Path B — via the CLI (10 minutes)&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">What you need</p><ul><li>Node.js 20+</li><li>A wallet private key with Base Sepolia ETH</li><li>A free <a href="https://app.pinata.cloud/keys" target="_blank" rel="noreferrer">Pinata</a> JWT (for IPFS metadata pinning)</li></ul></div><h3 id="step-1-—-clone-and-install" tabindex="-1">Step 1 — Clone and install <a class="header-anchor" href="#step-1-—-clone-and-install" aria-label="Permalink to &quot;Step 1 — Clone and install&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/rsilvestre/agent-birth-certificate.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agent-birth-certificate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="step-2-—-configure-env" tabindex="-1">Step 2 — Configure <code>.env</code> <a class="header-anchor" href="#step-2-—-configure-env" aria-label="Permalink to &quot;Step 2 — Configure \`.env\`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>Edit <code>.env</code> with your values:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Your creator wallet&#39;s private key (Base Sepolia ETH in it)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEPLOYER_PRIVATE_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0x...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Pinata JWT — free at https://app.pinata.cloud/keys (Files:Write scope)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PINATA_JWT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">eyJhbGc...</span></span></code></pre></div><h3 id="step-3-—-write-an-agent-identity-file" tabindex="-1">Step 3 — Write an agent identity file <a class="header-anchor" href="#step-3-—-write-an-agent-identity-file" aria-label="Permalink to &quot;Step 3 — Write an agent identity file&quot;">​</a></h3><p>Start from the example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/agent-nova.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/my-agent.json</span></span></code></pre></div><p>Edit <code>my-agent.json</code> with your agent&#39;s name, purpose, first thought, and optional fields.</p><h3 id="step-4-—-dry-run-to-preview" tabindex="-1">Step 4 — Dry-run to preview <a class="header-anchor" href="#step-4-—-dry-run-to-preview" aria-label="Permalink to &quot;Step 4 — Dry-run to preview&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-register.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/my-agent.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span></code></pre></div><p>This prints the metadata that would be pinned and the wallet address that would be generated, without sending any transactions.</p><h3 id="step-5-—-register-for-real" tabindex="-1">Step 5 — Register for real <a class="header-anchor" href="#step-5-—-register-for-real" aria-label="Permalink to &quot;Step 5 — Register for real&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-register.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/my-agent.json</span></span></code></pre></div><p>You&#39;ll be prompted for a keystore password (each keystroke echoes as <code>*</code>). The script will:</p><ol><li>Generate a fresh wallet for the agent</li><li>Pin metadata to Pinata (IPFS)</li><li>Call <code>registerAgent()</code> from your creator wallet</li><li>Immediately call <code>delegate()</code> granting 365-day authority to the agent&#39;s wallet</li><li>Save the encrypted keystore to <code>agents/&lt;name&gt;-&lt;id&gt;.json</code></li></ol><p>The final output prints the agent&#39;s ID, wallet, IPFS gateway, and explorer link.</p><h3 id="step-6-—-fund-the-agent-s-wallet" tabindex="-1">Step 6 — Fund the agent&#39;s wallet <a class="header-anchor" href="#step-6-—-fund-the-agent-s-wallet" aria-label="Permalink to &quot;Step 6 — Fund the agent&#39;s wallet&quot;">​</a></h3><p>Send 0.001 ETH (Base Sepolia) to the agent&#39;s wallet address. From MetaMask, or via <code>cast</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0xAGENT_WALLET</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.001ether</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --private-key</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $DEPLOYER_PRIVATE_KEY </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --rpc-url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://sepolia.base.org</span></span></code></pre></div><p>Now your agent can sign its own transactions.</p><h3 id="step-7-—-verify-the-agent-is-live" tabindex="-1">Step 7 — Verify the agent is live <a class="header-anchor" href="#step-7-—-verify-the-agent-is-live" aria-label="Permalink to &quot;Step 7 — Verify the agent is live&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/agent-action.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>You&#39;ll see the full on-chain identity — chosen name, purpose, first thought, creator, delegation, operational state.</p><hr><h2 id="what-s-next" tabindex="-1">What&#39;s next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next?&quot;">​</a></h2><ul><li><strong><a href="/docs/guides/act-as-agent">Guide: Act as an agent</a></strong> — update capabilities, request attestations, change status from the agent&#39;s own wallet</li><li><strong><a href="/docs/guides/issue-attestation">Guide: Issue an attestation</a></strong> — vouch for an agent&#39;s skills or credentials as an authority</li><li><strong><a href="/docs/concepts/civil-registry">Concepts: Civil registry model</a></strong> — why the project is structured this way</li><li><strong><a href="/docs/reference/cli">Reference: CLI commands</a></strong> — complete command reference</li></ul>`,46)])])}const k=a(n,[["render",l]]);export{c as __pageData,k as default};
